 import org.ascn.webservices.TableauHelper;
 import sailpoint.object.Identity;
 import sailpoint.object.ProvisioningPlan;
 import sailpoint.object.ProvisioningPlan.AccountRequest;
 import sailpoint.tools.GeneralException;

 String logName = "ASCN-Tableau-BeforeOperation";
 trace(logName, " Entering in " + logName);
 String sitePrefix = "AN";
 String arOperation = null;
 TableauHelper th = new TableauHelper();
 String contentType = "application/xml";
 String acceptType = "application/json";

 String outToken = th.getToken(sitePrefix);
 String accountId = th.getAccountId(provisioningPlan);
 arOperation = th.getArOperation();
 Map requestHeader = new HashMap();
 try {
     if (null != outToken) {
         //Executed when Disable Operation is executed.
         if (null != accountId && null != arOperation && "Disable".equals(arOperation)) {
             String userUrl = requestEndPoint.getFullUrl() + "/" + accountId;
             requestEndPoint.setFullUrl(userUrl);
             contentType = "application/xml";
         }
         requestHeader.put("X-Tableau-Auth", outToken);
         requestHeader.put("Accept", acceptType);
         requestHeader.put("Content-Type", contentType);
         requestEndPoint.setHeader(requestHeader);
     } else {
         trace(logName, " Error in " + logName + " Empty Token Returned / Token is NULL");
         throw new Exception("Empty Token Returned / Token is NULL");
     }
 } catch (Exception e) {
     error(logName, " Error in " + logName + " " + e, e);
 }
 trace(logName, " Exiting in " + logName);
 return requestEndPoint;
